const body = $input.first().json.body || $input.first().json;

const youtubeUrl = body.youtube_url || body.url || body.youtube || body.input_url;
let useGemini = true;

if (body.method !== undefined) {
  const m = body.method;
  if (Array.isArray(m)) {
    const lowered = m.map(x => String(x).toLowerCase());
    if (lowered.includes('whisper') && !lowered.includes('gemini')) {
      useGemini = false;
    } else if (lowered.includes('gemini') && !lowered.includes('whisper')) {
      useGemini = true;
    } else {
      useGemini = true;
    }
  } else {
    const ms = String(m).toLowerCase();
    useGemini = (ms === 'gemini' || ms === 'true' || ms === '1' || ms === 'yes');
  }
} else if (body.use_gemini !== undefined) {
  const ug = body.use_gemini;
  if (typeof ug === 'boolean') {
    useGemini = ug;
  } else {
    const s = String(ug).toLowerCase();
    useGemini = (s === 'true' || s === '1' || s === 'yes' || s === 'gemini');
  }
}

if (!youtubeUrl) {
  throw new Error('URL YouTube manquante');
}

const youtubeRegex = /(?:youtube\.com\/(?:[^\/]+\/.+\/|(?:v|e(?:mbed)?)\/|.*[?&]v=)|youtu\.be\/)([^"&?\/ ]{11})/;
const match = youtubeUrl.match(youtubeRegex);

if (!match || !match[1]) {
  throw new Error('URL YouTube invalide');
}

return [{
  json: {
    youtube_url: youtubeUrl,
    video_id: match[1],
    use_gemini: useGemini,
    timestamp: new Date().toISOString()
  }
}];

