  const content = response.candidates[0].content;
  if (content && content.parts) {
    transcriptionText = content.parts.map(p => p.text).join('');
  }
}

if (!transcriptionText) {
  throw new Error('Pas de transcription reçue de Gemini');
}

return [{
  json: {
    video_id: videoId,
    transcription: transcriptionText,
    method: 'gemini',
