  fs.mkdirSync(outputDir, { recursive: true });
}

const transcriptionPath = path.join(outputDir, 'transcription_brute.txt');
fs.writeFileSync(transcriptionPath, transcriptionText);

const metadata = {
  video_id: videoId,
  youtube_url: $('Extraire Video ID').first().json.youtube_url,
  transcription_method: method,
  transcription_date: new Date().toISOString(),
